#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int countSubstrings(char *s) {
    int n = strlen(s);
    int count = 0;
    for (int len = 1; len <= n; len++) {
        for (int i = 0; i <= n - len; i++) {
            char substr[len + 1];
            strncpy(substr, s + i, len);
            substr[len] = '\0';
            int found = 0;
            for (int j = 0; j < i; j++) {
                if (strncmp(s + j, substr, len) == 0) {
                    found = 1;
                    break;
                }
            }
            if (!found) count++;
        }
    }
    return count;
}

void backtrack(char *s, int n, int k, int idx, int *count) {
    if (idx == n) {
        int substrCount = countSubstrings(s);
        if (substrCount <= k) (*count)++;
        return;
    }
    if (s[idx] == '?') {
        s[idx] = '4';
        backtrack(s, n, k, idx + 1, count);
        s[idx] = '7';
        backtrack(s, n, k, idx + 1, count);
        s[idx] = '?';
    } else {
        backtrack(s, n, k, idx + 1, count);
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        char s[n + 1];
        scanf("%s", s);
        int count = 0;
        backtrack(s, n, k, 0, &count);
        printf("%d\n", count);
    }
    return 0;
}

