import java.util.Scanner;
public class Main {
    public static int countSubstrings(String s) {
        int n = s.length();
        int count = 0;
        for (int len = 1; len <= n; len++) {
            for (int i = 0; i <= n - len; i++) {
                String substr = s.substring(i, i + len);
                int found = 0;
                for (int j = 0; j < i; j++) {
                    if (s.substring(j, j + len).equals(substr)) {
                        found = 1;
                        break;
                    }
                }
                if (found == 0) count++;
            }
        }
        return count;
    }

    public static void backtrack(StringBuilder s, int n, int k, int idx, int[] count) {
        if (idx == n) {
            int substrCount = countSubstrings(s.toString());
            if (substrCount <= k) count[0]++;
            return;
        }
        if (s.charAt(idx) == '?') {
            s.setCharAt(idx, '4');
            backtrack(s, n, k, idx + 1, count);
            s.setCharAt(idx, '7');
            backtrack(s, n, k, idx + 1, count);
            s.setCharAt(idx, '?');
        } else {
            backtrack(s, n, k, idx + 1, count);
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            StringBuilder s = new StringBuilder(sc.next());
            int[] count = new int[1];
            backtrack(s, n, k, 0, count);
            System.out.println(count[0]);
        }
    }
}

