import sys

def count_substrings(s):
    n = len(s)
    count = 0
    for length in range(1, n + 1):
        for i in range(n - length + 1):
            substr = s[i:i + length]
            found = False
            for j in range(i):
                if s[j:j + length] == substr:
                    found = True
                    break
            if not found: count += 1
    return count

def backtrack(s, n, k, idx, count):
    if idx == n:
        substr_count = count_substrings(s)
        if substr_count <= k: count[0] += 1
        return
    if s[idx] == '?':
        s[idx] = '4'
        backtrack(s, n, k, idx + 1, count)
        s[idx] = '7'
        backtrack(s, n, k, idx + 1, count)
        s[idx] = '?'
    else:
        backtrack(s, n, k, idx + 1, count)

